@namespace Lumeo
@implements IDisposable
@inject IComponentInteropService Interop

@* <gotcha>Data-bound mode (the Items parameter) still requires <ComboboxInput /> and <ComboboxContent /> children — a bare <Combobox Items="..." /> with no children renders only an empty wrapper. Map items with ItemValue/ItemText (there is no ItemLabel parameter); items are typed as object, so the Combobox is not generic (no TItem).</gotcha> *@

@{
    var navItems = NavItems;
    var focusedItemId = _focusedIndex >= 0 && _focusedIndex < navItems.Count ? navItems[_focusedIndex].Id : null;
    var focusedItemValue = _focusedIndex >= 0 && _focusedIndex < navItems.Count ? navItems[_focusedIndex].Value : null;
    var context = new ComboboxContext(Value, Values, SearchText, Open, Multiple, IsSearchLoading, Creatable,
        EventCallback.Factory.Create<string>(this, OnValueSelected),
        EventCallback.Factory.Create<bool>(this, SetOpen),
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        EventCallback.Factory.Create<string>(this, OnCreateItem),
        _wrapperId, _contentId, _inputId, _focusedIndex, focusedItemId, focusedItemValue,
        EventCallback.Factory.Create<int>(this, SetFocusedIndex),
        RegisterItem, UnregisterItem, _items.Count, EffectiveInvalid, Required,
        Items, ItemValue, ItemText, ItemGroup, ItemDisabled, ItemDescription, ItemIcon, ItemTemplate, Virtualize, ItemSize)
    {
        Placeholder = Placeholder,
        DescribedBy = FormFieldDescribedBy,
        Clearable = Clearable,
        MaxDisplayTags = MaxDisplayTags,
        OnClear = EventCallback.Factory.Create(this, OnClearSelection),
        MostRecentValue = _valueOrder.Count > 0 ? _valueOrder[^1] : null,
    };
}

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="@WrapperCssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // Threaded into ComboboxContext.DescribedBy → ComboboxInput's aria-describedby.
    // The input keeps its own _inputId (load-bearing for popover anchoring), so the
    // FormField <Label For> can't click-focus it, but the help/error association lands.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    /// <summary>
    /// Popover open state. Bind via <c>@bind-Open</c> when the Combobox lives inside
    /// a parent that re-renders heavily (e.g. an <c>EditForm</c> with active
    /// validation) — otherwise a parameter cascade can close the popover mid-click.
    /// In the bound (controlled) mode the parent owns state and the popover survives
    /// re-renders. When unbound, the component still functions but is vulnerable to
    /// the cascade-close race; binding is the recommended pattern.
    /// </summary>
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Multi-select
    [Parameter] public bool Multiple { get; set; }
    [Parameter] public HashSet<string>? Values { get; set; }
    [Parameter] public EventCallback<HashSet<string>> ValuesChanged { get; set; }
    /// <summary>Cap on the number of selected-value chips rendered by
    /// <see cref="ComboboxInput"/> in <see cref="Multiple"/> mode; the rest collapse into a
    /// "+N more" indicator. Mirrors <c>Select.MaxDisplayTags</c>.</summary>
    [Parameter] public int MaxDisplayTags { get; set; } = 3;
    /// <summary>When <c>true</c>, the input shows a clear (×) affordance that resets
    /// <see cref="Value"/> (or <see cref="Values"/> in <see cref="Multiple"/> mode) to its empty
    /// state. Mirrors <c>Select.Clearable</c>.</summary>
    [Parameter] public bool Clearable { get; set; }

    // Creatable
    [Parameter] public bool Creatable { get; set; }
    [Parameter] public EventCallback<string> OnCreate { get; set; }

    // Async search
    [Parameter] public EventCallback<string> OnSearchAsync { get; set; }
    [Parameter] public int DebounceMs { get; set; } = 300;
    [Parameter] public bool IsSearchLoading { get; set; }

    // Validation
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    /// <summary>Custom CSS classes merged onto the Combobox's wrapper element. Consistent
    /// with every other form component per the library's base API contract.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Convenience placeholder shown by <see cref="ComboboxInput"/> when it doesn't
    /// set its own <c>Placeholder</c>. Lets consumers write <c>&lt;Combobox Placeholder="…"&gt;</c>
    /// instead of threading it through the input child.</summary>
    [Parameter] public string? Placeholder { get; set; }
    /// <summary>Focuses the combobox text input on first render. See
    /// <c>Input.AutoFocus</c> — the HTML autofocus attribute doesn't work
    /// in Blazor WASM, this parameter uses <c>FocusElement</c> after the
    /// component has mounted.</summary>
    [Parameter] public bool AutoFocus { get; set; }

    /// <summary>Programmatically focus the combobox text input.</summary>
    public ValueTask FocusAsync() => Interop.FocusElement(_inputId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await Interop.FocusElement(_inputId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    // --- Data-bound mode (non-generic, purely additive) ---
    /// <summary>Optional data source. When set, <see cref="ComboboxContent"/> renders options from this list instead of ChildContent.</summary>
    [Parameter] public IEnumerable<object>? Items { get; set; }
    /// <summary>Extracts the string value for each item. Defaults to <c>ToString()</c>.</summary>
    [Parameter] public Func<object, string> ItemValue { get; set; } = it => it?.ToString() ?? "";
    /// <summary>Extracts the display label for each item. Defaults to <see cref="ItemValue"/> when null.</summary>
    [Parameter] public Func<object, string>? ItemText { get; set; }
    /// <summary>Optional group key extractor. When set, options are grouped under sticky headers.</summary>
    [Parameter] public Func<object, string?>? ItemGroup { get; set; }
    /// <summary>Optional per-item disabled predicate.</summary>
    [Parameter] public Func<object, bool>? ItemDisabled { get; set; }
    /// <summary>
    /// Optional per-item secondary line (description) extractor. When set and
    /// <see cref="ItemTemplate"/> is null, the default item renderer shows the
    /// description in a smaller, muted line below the label — the standard pattern
    /// for command pickers (vscode-style "label + helper text").
    /// </summary>
    [Parameter] public Func<object, string?>? ItemDescription { get; set; }
    /// <summary>
    /// Optional per-item leading icon. Receives the raw item object and returns a
    /// RenderFragment (typically a single <c>&lt;Blazicon&gt;</c>). Rendered before
    /// the label when <see cref="ItemTemplate"/> is null. Skip via returning
    /// <c>null</c> per item to mix iconed and non-iconed rows.
    /// </summary>
    [Parameter] public Func<object, RenderFragment?>? ItemIcon { get; set; }
    /// <summary>Optional custom render fragment for an item's content. Receives the raw item object.</summary>
    [Parameter] public RenderFragment<object>? ItemTemplate { get; set; }
    /// <summary>When <c>true</c> and <see cref="Items"/> is set, uses Blazor's Virtualize component for the option list.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated pixel height of each option row used by the Virtualize component. Default 36.</summary>
    [Parameter] public float ItemSize { get; set; } = 36f;

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // "relative" anchors the absolutely-positioned dropdown; Class is merged after so
    // consumers can append (or override) wrapper styling like every other form control.
    private string WrapperCssClass => Cx.Merge("relative", Class);

    private readonly string _wrapperId = LumeoIds.New("combobox");
    private readonly string _contentId = LumeoIds.New("combobox-content");
    private readonly string _inputId = LumeoIds.New("combobox-input");
    private string SearchText { get; set; } = "";
    private readonly DelayedDispatch _dispatch = new();
    private int _focusedIndex = -1;
    private readonly List<(string Id, string Value)> _items = new();
    // Insertion-ordered mirror of the (unordered) Values HashSet — see SyncValueOrder.
    private readonly List<string> _valueOrder = new();

    protected override void OnParametersSet() => SyncValueOrder();

    // Mirrors the consumer-owned Values set into an insertion-ordered list so chip-editing
    // keys (Backspace in ComboboxInput) can deterministically target the most recently
    // added value — HashSet enumeration order is undefined, so Values.Last() removed an
    // arbitrary chip. Comparisons go through the set's own comparer so custom equality
    // (e.g. StringComparer.OrdinalIgnoreCase, preserved by Clear since PR #165) is
    // respected. Values added through the UI append chronologically; values that arrive
    // in bulk from the consumer append in enumeration order (no history exists for them).
    private void SyncValueOrder()
    {
        if (Values is null || Values.Count == 0)
        {
            _valueOrder.Clear();
            return;
        }
        _valueOrder.RemoveAll(v => !Values.Contains(v));
        foreach (var v in Values)
        {
            if (!_valueOrder.Contains(v, Values.Comparer))
                _valueOrder.Add(v);
        }
    }

    private void RegisterItem(string id, string value)
    {
        if (!_items.Any(i => i.Id == id))
            _items.Add((id, value));
    }

    private void UnregisterItem(string id)
    {
        _items.RemoveAll(i => i.Id == id);
    }

    // Keyboard-nav source of truth. Composition mode: ComboboxItem instances self-register
    // into _items. Data-bound mode: bound rows are rendered inline by ComboboxContent (no
    // component instance to register), so derive the list from the same filtered + grouped
    // sequence the content renders, skipping disabled items so ArrowDown/Up, Home/End and
    // Enter can never land on them. Ids must mirror ComboboxContent.RenderBoundItem.
    private List<(string Id, string Value)> NavItems => Items is null ? _items : BuildBoundNavItems();

    private List<(string Id, string Value)> BuildBoundNavItems()
    {
        var result = new List<(string Id, string Value)>();
        if (Items is null) return result;

        IEnumerable<object> source = Items;
        if (!string.IsNullOrEmpty(SearchText))
        {
            source = source.Where(item =>
            {
                var text = ItemText?.Invoke(item) ?? ItemValue(item);
                return text.Contains(SearchText, StringComparison.OrdinalIgnoreCase);
            });
        }
        // Grouped rendering flattens GroupBy order (groups appear at their first occurrence),
        // so mirror it — otherwise the focused index walks the source order while the eye
        // follows the grouped order. The Virtualize branch renders ungrouped.
        if (ItemGroup is not null && !Virtualize)
            source = source.GroupBy(i => ItemGroup(i) ?? "").SelectMany(g => g);

        // Index increments for EVERY item (disabled included) so it stays the item's position
        // in the rendered sequence — ComboboxContent.RenderBoundItem assigns the same per-position
        // id. Disabled items are skipped from the nav list but still consume an index slot so the
        // enabled rows keep the id their rendered counterpart computed. Using the position (not
        // value.GetHashCode()) makes the ids collision-proof.
        var index = 0;
        foreach (var item in source)
        {
            var i = index++;
            if (ItemDisabled?.Invoke(item) == true) continue;
            var value = ItemValue(item);
            result.Add(($"{_contentId}-bound-{i}", value));
        }
        return result;
    }

    private async Task SetFocusedIndex(int index)
    {
        var count = NavItems.Count;
        if (count == 0) return;
        if (index < 0) index = 0;
        if (index >= count) index = count - 1;
        _focusedIndex = index;
        StateHasChanged();
        await Task.CompletedTask;
    }

    private async Task OnValueSelected(string value)
    {
        if (Multiple)
        {
            Values ??= [];
            if (Values.Contains(value))
                Values.Remove(value);
            else
                Values.Add(value);
            // Sync here as well as in OnParametersSet: unbound usage (no ValuesChanged
            // handler) never produces a fresh parameter pass, so the order mirror would
            // go stale and Backspace would fall back to arbitrary removal.
            SyncValueOrder();
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
    }

    private async Task SetOpen(bool value)
    {
        Open = value;
        if (!value && !Multiple)
        {
            SearchText = "";
            _focusedIndex = -1;
            _items.Clear();
        }
        await OpenChanged.InvokeAsync(value);
    }

    private async Task OnSearchChanged(string text)
    {
        SearchText = text;
        _focusedIndex = -1;

        // Never clear _items here — for static AND async search alike, ComboboxItems own
        // their registration lifecycle: items hidden/unmounted by the new results unregister
        // themselves (OnParametersSet/Dispose) and new ones register on mount. Clearing
        // orphaned the still-mounted survivors (their _registered flag stays true, so they
        // never re-register), which killed keyboard nav and mis-reported ItemCount as 0 —
        // showing the ComboboxEmpty state underneath live results.
        if (OnSearchAsync.HasDelegate)
        {
            _dispatch.Schedule(DebounceMs, () => InvokeAsync(async () =>
            {
                await OnSearchAsync.InvokeAsync(text);
                StateHasChanged();
            }));
        }

        await Task.CompletedTask;
    }

    private async Task OnClearSelection()
    {
        if (Multiple)
        {
            // Emit an empty set rather than null: ValuesChanged is typed as the
            // non-nullable EventCallback<HashSet<string>>, and consumers commonly
            // bind to a non-null `HashSet<string> _selected = new()` and read
            // `_selected.Count` during render — a null roundtrip via @bind-Values
            // would NRE there (Codex P2, PR #163). Preserve the bound set's
            // comparer (e.g. StringComparer.OrdinalIgnoreCase) when present,
            // otherwise the consumer loses case-insensitive equality semantics
            // after a Clear (Codex P2, PR #165).
            var comparer = Values?.Comparer ?? EqualityComparer<string>.Default;
            Values = new HashSet<string>(comparer);
            SyncValueOrder();
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = null;
            await ValueChanged.InvokeAsync(null);
        }
        SearchText = "";
    }

    private async Task OnCreateItem(string value)
    {
        await OnCreate.InvokeAsync(value);
        if (Multiple)
        {
            Values ??= [];
            Values.Add(value);
            SyncValueOrder();
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
        SearchText = "";
    }

    public void Dispose() => _dispatch.Dispose();

    public record ComboboxContext(
        string? Value, HashSet<string>? Values, string SearchText, bool IsOpen, bool Multiple, bool IsSearchLoading, bool Creatable,
        EventCallback<string> OnSelect, EventCallback<bool> SetOpen, EventCallback<string> OnSearch,
        EventCallback<string> OnCreateItem,
        string WrapperId, string ContentId, string InputId, int FocusedIndex, string? FocusedItemId, string? FocusedItemValue,
        EventCallback<int> SetFocusedIndex,
        Action<string, string> RegisterItem, Action<string> UnregisterItem, int ItemCount,
        bool Invalid, bool Required,
        // Data-bound mode params (null when composition mode)
        IEnumerable<object>? Items,
        Func<object, string> ItemValue,
        Func<object, string>? ItemText,
        Func<object, string?>? ItemGroup,
        Func<object, bool>? ItemDisabled,
        Func<object, string?>? ItemDescription,
        Func<object, RenderFragment?>? ItemIcon,
        RenderFragment<object>? ItemTemplate,
        bool Virtualize,
        float ItemSize)
    {
        /// <summary>Top-level placeholder set on <c>&lt;Combobox&gt;</c>; ComboboxInput uses it
        /// as a fallback when its own Placeholder is unset. Init-only so the positional
        /// constructor above stays source-compatible.</summary>
        public string? Placeholder { get; init; }
        public bool Clearable { get; init; }
        public int MaxDisplayTags { get; init; } = 3;
        public EventCallback OnClear { get; init; }
        /// <summary>The most recently added entry of <see cref="Values"/> (insertion order is
        /// tracked by the parent — the HashSet itself is unordered). Used by ComboboxInput's
        /// Backspace chip removal so it deterministically removes the newest chip.</summary>
        public string? MostRecentValue { get; init; }

        /// <summary>Id of the parent FormField's rendered help/error text, applied as
        /// <c>aria-describedby</c> on the combobox input so a screen reader announces it on
        /// focus. Null outside a FormField. Init-only to keep the positional ctor compatible.</summary>
        public string? DescribedBy { get; init; }
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@using Microsoft.AspNetCore.Components.Web.Virtualization

@if (Context.IsOpen)
{
    <div id="@Context.ContentId" role="listbox" aria-multiselectable="@(Context.Multiple ? "true" : null)" class="@CssClass"
         @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @if (Context.IsSearchLoading)
        {
            <div class="flex items-center justify-center py-2 px-2 text-sm text-muted-foreground">
                <Spinner Class="h-4 w-4 mr-2" />
                @L["Combobox.Loading"]
            </div>
        }
        @if (Context.Items is not null)
        {
            @* Data-bound mode *@
            var filteredItems = FilteredItems;
            @if (Context.Virtualize)
            {
                @* Pair each item with its positional index up-front. IndexOf would return
                   the FIRST equal item, so duplicate values collapsed to one id and desynced
                   from Combobox.BuildBoundNavItems' positional indexing. *@
                var indexedItems = filteredItems.Select((it, idx) => (Item: it, Index: idx)).ToList();
                <Virtualize Items="@indexedItems" Context="entry" ItemSize="@Context.ItemSize">
                    @RenderBoundItem(entry.Item, entry.Index)
                </Virtualize>
            }
            else if (Context.ItemGroup is not null)
            {
                @* Walk groups in order with a running index so each row's id matches the
                   flattened (GroupBy→SelectMany) order the parent uses for keyboard nav. *@
                var boundIndex = 0;
                @foreach (var group in filteredItems.GroupBy(i => Context.ItemGroup(i) ?? ""))
                {
                    <div role="group">
                        @if (!string.IsNullOrEmpty(group.Key))
                        {
                            <div class="px-2 py-1.5 text-sm font-semibold">@group.Key</div>
                        }
                        @foreach (var item in group)
                        {
                            @RenderBoundItem(item, boundIndex++)
                        }
                    </div>
                }
            }
            else
            {
                @for (var i = 0; i < filteredItems.Count; i++)
                {
                    @RenderBoundItem(filteredItems[i], i)
                }
            }

            @if (filteredItems.Count == 0 && !Context.IsSearchLoading)
            {
                <div class="py-6 text-center text-sm text-muted-foreground">
                    @(EmptyText ?? L["Combobox.NoResults"])
                </div>
            }

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText) && filteredItems.Count == 0)
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 px-2 text-sm outline-none hover:bg-accent hover:text-accent-foreground border-t border-border/40 mt-1 pt-2"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
        else
        {
            @* Composition mode *@
            @ChildContent
            @if (!Context.IsSearchLoading && Context.ItemCount == 0 && ChildContent is null)
            {
                @* Fallback default empty — only renders if the consumer didn't supply any children at all.
                   The real empty state is `<ComboboxEmpty>` which renders itself when ItemCount hits 0. *@
                <div class="py-6 text-center text-sm text-muted-foreground">
                    @(EmptyText ?? L["Combobox.NoResults"])
                </div>
            }
            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText) && Context.ItemCount == 0)
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 px-2 text-sm outline-none hover:bg-accent hover:text-accent-foreground border-t border-border/40 mt-1 pt-2"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? EmptyText { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;

    private string CssClass => Cx.Merge("fixed z-50 overflow-hidden rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", Class);

    // Items filtered by the current search text (data-bound mode only).
    //
    // Previously a computed property: at 10k items it ran the Where+ToList for
    // every access, and the markup above accesses it 3+ times per render
    // (Virtualize Items, foreach, Count checks). Now we memoize: recompute
    // only when the Items reference changes OR the search text changes.
    // Invalidation happens in OnParametersSet — any external state mutation
    // that flows through a parameter pass (which is the only way Combobox
    // updates its descendants) gets picked up.
    // Keep the concrete type List<object> — the markup uses .Count and passes
    // this list to <Virtualize Items=...> which wants an ICollection<T>.
    private List<object> _filteredItems = new();
    private IEnumerable<object>? _lastItems;
    private string? _lastSearchText;

    private List<object> FilteredItems => _filteredItems;

    protected override void OnParametersSet()
    {
        var items = Context?.Items;
        var search = Context?.SearchText;

        if (!ReferenceEquals(items, _lastItems) || !string.Equals(search, _lastSearchText, StringComparison.Ordinal))
        {
            _lastItems = items;
            _lastSearchText = search;
            _filteredItems = ComputeFiltered(items, search);
        }
    }

    private List<object> ComputeFiltered(IEnumerable<object>? items, string? searchText)
    {
        if (items is null) return new();
        if (string.IsNullOrEmpty(searchText))
            return items.ToList();

        return items.Where(item =>
        {
            var text = Context.ItemText?.Invoke(item) ?? Context.ItemValue(item);
            return text.Contains(searchText, StringComparison.OrdinalIgnoreCase);
        }).ToList();
    }

    private RenderFragment RenderBoundItem(object item, int index) => builder =>
    {
        var value = Context.ItemValue(item);
        var isSelected = Context.Multiple
            ? Context.Values?.Contains(value) == true
            : Context.Value == value;
        var isDisabled = Context.ItemDisabled?.Invoke(item) ?? false;
        // Per-instance ContentId prefix + position index (never value.GetHashCode()):
        // hash-derived ids collided across equal values AND across two open Comboboxes.
        // The index is the item's position in the filtered (+ grouped) sequence — the same
        // basis Combobox.BuildBoundNavItems uses, keeping the rendered id and nav id in sync.
        var itemId = $"{Context.ContentId}-bound-{index}";
        var isFocused = Context.FocusedItemId == itemId;

        builder.OpenElement(0, "button");
        builder.AddAttribute(1, "type", "button");
        builder.AddAttribute(2, "id", itemId);
        builder.AddAttribute(3, "role", "option");
        builder.AddAttribute(4, "aria-selected", isSelected.ToString().ToLower());
        // Disabled bound rows mirror Select: announce aria-disabled and swap the interactive
        // styling for the muted/not-allowed treatment (BuildBoundNavItems already drops them
        // from keyboard nav, and onclick is suppressed below).
        builder.AddAttribute(5, "aria-disabled", isDisabled.ToString().ToLower());
        var cssClass = Cx.Join(
            "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none",
            isDisabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
            Cx.When(isFocused && !isDisabled, "bg-accent text-accent-foreground"));
        builder.AddAttribute(6, "class", cssClass);
        if (!isDisabled)
        {
            builder.AddAttribute(7, "onclick", EventCallback.Factory.Create(this, () => Context.OnSelect.InvokeAsync(value)));
        }
        builder.OpenElement(8, "span");
        builder.AddAttribute(9, "class", "flex h-3.5 w-3.5 items-center justify-center");
        if (isSelected)
        {
            builder.OpenComponent<Blazicons.Blazicon>(10);
            builder.AddAttribute(11, "Svg", Blazicons.Lucide.Check);
            builder.AddAttribute(12, "class", "h-3.5 w-3.5");
            builder.CloseComponent();
        }
        builder.CloseElement(); // span

        if (Context.ItemTemplate is not null)
        {
            builder.AddContent(13, Context.ItemTemplate(item));
        }
        else
        {
            // Default renderer: optional leading icon, label, optional sub-line description.
            // ItemIcon and ItemDescription return null per item to mix iconed / un-iconed
            // rows in the same list without forcing every row to allocate the icon column.
            var icon = Context.ItemIcon?.Invoke(item);
            if (icon is not null)
            {
                builder.OpenElement(13, "span");
                builder.AddAttribute(14, "class", "flex h-4 w-4 shrink-0 items-center justify-center text-muted-foreground");
                builder.AddContent(15, icon);
                builder.CloseElement();
            }

            var label = Context.ItemText?.Invoke(item) ?? value;
            var description = Context.ItemDescription?.Invoke(item);
            if (!string.IsNullOrEmpty(description))
            {
                builder.OpenElement(16, "span");
                builder.AddAttribute(17, "class", "flex min-w-0 flex-col");
                builder.OpenElement(18, "span");
                builder.AddAttribute(19, "class", "truncate");
                builder.AddContent(20, label);
                builder.CloseElement();
                builder.OpenElement(21, "span");
                builder.AddAttribute(22, "class", "truncate text-xs text-muted-foreground");
                builder.AddContent(23, description);
                builder.CloseElement();
                builder.CloseElement();
            }
            else
            {
                builder.AddContent(24, label);
            }
        }
        builder.CloseElement(); // button
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, "start", true);
            // Exclude the combobox wrapper from outside-close (same as Popover): the "trigger"
            // here is the input plus its chip wrapper, which has no id of its own — the
            // WrapperId covers them all. Without the exclusion, mousedown on the input/chips
            // fires the outside handler and races the input's own open logic.
            await Interop.RegisterClickOutside(Context.ContentId, Context.WrapperId, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
        }
    }

    private async Task HandleCreate()
    {
        await Context.OnCreateItem.InvokeAsync(Context.SearchText);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

