    {
        var text = e.Value?.ToString() ?? "";
        await Context.OnSearch.InvokeAsync(text);
        if (!Context.IsOpen)
        {
            await Context.SetOpen.InvokeAsync(true);
        }
    }

    private async Task Open()
    {
        if (!Context.IsOpen)
        {
            await Context.SetOpen.InvokeAsync(true);
        }
    }

    private async Task RemoveValue(string value) => await Context.OnSelect.InvokeAsync(value);

    private async Task HandleClear() => await Context.OnClear.InvokeAsync();

    // Wrapper click handler for chip-mode layouts: opens the dropdown and focuses
    // the inline search input so clicks on chip text or empty space inside the
    // wrapper aren't dead zones (Codex P2, PR #165).
    private async Task OpenAndFocus()
    {
        if (!Context.IsOpen)
            await Context.SetOpen.InvokeAsync(true);
        try { await Interop.FocusElement(Context.InputId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
    }

    // Resolve a stored value to its human-friendly display label. Data-bound
    // mode: look up the item via ItemValue and use ItemText. Composition mode
    // (Items==null) has no value→label registry, so the raw value is the best
    // we can do — same as v3.12.0 multi-chip behavior (Codex P2, PR #165).
    private string ItemDisplay(string val)
    {
        if (Context.Items != null)
        {
            foreach (var item in Context.Items)
            {
                if (Context.ItemValue(item) == val)
                    return Context.ItemText?.Invoke(item) ?? Context.ItemValue(item);
            }
        }
        return val;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.IsOpen && Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "Backspace":
                // Tag-input convention: when the search field is empty and Multiple has
                // selections, Backspace removes the most recently added chip. The parent
                // tracks insertion order (MostRecentValue) because HashSet enumeration
                // order is undefined — Values.Last() removed an arbitrary chip after any
                // remove-then-add sequence. Single mode is unchanged.
                if (Context.Multiple && string.IsNullOrEmpty(Context.SearchText) && Context.Values is { Count: > 0 })
                {
                    var newest = Context.MostRecentValue ?? Context.Values.Last();
                    await Context.OnSelect.InvokeAsync(newest);
                }
                break;
        }
    }

    private bool _pdRegistered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // Suppress the input's caret motion for the keys that drive the listbox,
            // so ArrowUp/Down navigate options (instead of jumping the text caret) and
            // a plain Enter selects the active option rather than submitting an
            // enclosing form. Same set as Command. NOT SkipEditable — unlike Select's
            // listbox, the handler here must fire ON the editable input itself.
            await Interop.RegisterPreventDefaultKeys(Context.InputId, new[]
            {
                new PreventDefaultKeyRule("ArrowDown", SkipComposing: true),
                new PreventDefaultKeyRule("ArrowUp", SkipComposing: true),
                new PreventDefaultKeyRule("Enter", RequireNoModifiers: true, SkipComposing: true),
            });
            _pdRegistered = true;
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(Context.InputId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@implements IDisposable

@if (Visible)
{
    <button type="button" id="@_itemId" role="option" aria-selected="@IsSelected.ToString().ToLower()"
            aria-disabled="@Disabled.ToString().ToLower()"
            class="@CssClass" style="@IndentStyle" @onclick="HandleSelect" @attributes="AdditionalAttributes">
        <span class="flex h-3.5 w-3.5 items-center justify-center">
            @if (IsSelected)
            {
                <Blazicon Svg="Lucide.Check" class="h-3.5 w-3.5" />
            }
        </span>
        @ChildContent
    </button>
}

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    // Present when the item sits inside one or more ComboboxGroups (nearest group wins).
    [CascadingParameter] public ComboboxGroup.ComboboxGroupContext? Group { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    /// <summary>When <c>true</c>, the item renders muted/non-interactive, announces
    /// <c>aria-disabled</c> and cannot be selected by click — mirrors <c>SelectItem.Disabled</c>.</summary>
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>Optional text used to match against the search input. Falls back to Value.</summary>
    [Parameter] public string? SearchValue { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("combobox-item");
    private bool _registered;
    private bool _groupRegistered;

    // Indent items one extra step beyond their group's header for visual nesting.
    private string IndentStyle => Group is { Depth: var d } && d >= 0
        ? $"padding-left:{0.5 + (d + 1) * 0.75:0.###}rem"
        : "";

    private bool IsSelected => Context.Multiple
        ? Context.Values?.Contains(Value) == true
        : Context.Value == Value;

    private bool IsFocused => Context.FocusedItemId == _itemId;

    // True when the item should render as a navigable option in the listbox. A collapsed
    // ancestor group hides its items entirely (and removes them from keyboard nav), but the
    // item still registers with the group below so GroupSelect can see / mutate the
    // descendants even while collapsed.
    private bool Visible
    {
        get
        {
            // EffectiveIsExpanded (not just IsExpanded) so a collapsed outer group hides
            // inner items even when their immediate group is locally expanded.
            if (Group is { EffectiveIsExpanded: false }) return false;
            return PassesSearchFilter;
        }
    }

    // Just the search check — used to drive the group's empty-hiding and aggregate state
    // without coupling it to the collapsed/expanded view.
    private bool PassesSearchFilter
    {
        get
        {
            if (string.IsNullOrEmpty(Context.SearchText)) return true;
            var haystack = SearchValue ?? Value;
            return haystack.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
        }
    }

    private string CssClass => Cx.Merge(
        "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none",
        Disabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
        Cx.When(IsFocused && !Disabled, "bg-accent text-accent-foreground"),
        Class);

    protected override void OnParametersSet()
    {
        // Disabled items are kept out of the nav registry (mirroring the data-bound
        // path) so roving keyboard nav / Enter never lands on a disabled row; the
        // guard in HandleSelect is the second line of defense.
        if (Visible && !Disabled && !_registered)
        {
            Context.RegisterItem(_itemId, Value);
            _registered = true;
        }
        else if ((!Visible || Disabled) && _registered)
        {
            Context.UnregisterItem(_itemId);
            _registered = false;
        }

        // Report value + search visibility to the enclosing group. We use PassesSearchFilter
        // (not Visible) so a collapsed group still sees its descendants for GroupSelect's
        // tri-state aggregation and select-all toggle.
        if (Group is not null)
        {
            Group.RegisterItem(_itemId, Value, PassesSearchFilter);
            _groupRegistered = true;
        }
    }

    public void Dispose()
    {
        if (_registered) Context.UnregisterItem(_itemId);
        if (_groupRegistered) Group?.UnregisterItem(_itemId);
    }

    private async Task HandleSelect()
    {
        if (Disabled) return;
        await Context.OnSelect.InvokeAsync(Value);
    }
}
